def _dynamo_db_secondary_index_to_nested(
    dynamo_db_secondary_index: DynamoDBSecondaryIndex,
) -> DynamoDBSecondaryIndexNested:
    """Convert flat DynamoDBSecondaryIndex to nested format."""
    attrs = DynamoDBSecondaryIndexAttributes()
    _populate_dynamo_db_secondary_index_attrs(attrs, dynamo_db_secondary_index)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dynamo_db_secondary_index,
        _DYNAMO_DB_SECONDARY_INDEX_REL_FIELDS,
        DynamoDBSecondaryIndexRelationshipAttributes,
    )
    return DynamoDBSecondaryIndexNested(
        guid=dynamo_db_secondary_index.guid,
        type_name=dynamo_db_secondary_index.type_name,
        status=dynamo_db_secondary_index.status,
        version=dynamo_db_secondary_index.version,
        create_time=dynamo_db_secondary_index.create_time,
        update_time=dynamo_db_secondary_index.update_time,
        created_by=dynamo_db_secondary_index.created_by,
        updated_by=dynamo_db_secondary_index.updated_by,
        classifications=dynamo_db_secondary_index.classifications,
        classification_names=dynamo_db_secondary_index.classification_names,
        meanings=dynamo_db_secondary_index.meanings,
        labels=dynamo_db_secondary_index.labels,
        business_attributes=dynamo_db_secondary_index.business_attributes,
        custom_attributes=dynamo_db_secondary_index.custom_attributes,
        pending_tasks=dynamo_db_secondary_index.pending_tasks,
        proxy=dynamo_db_secondary_index.proxy,
        is_incomplete=dynamo_db_secondary_index.is_incomplete,
        provenance_type=dynamo_db_secondary_index.provenance_type,
        home_id=dynamo_db_secondary_index.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dynamo_db_secondary_index_from_nested(
    nested: DynamoDBSecondaryIndexNested,
) -> DynamoDBSecondaryIndex:
    """Convert nested format to flat DynamoDBSecondaryIndex."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DynamoDBSecondaryIndexAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DYNAMO_DB_SECONDARY_INDEX_REL_FIELDS,
        DynamoDBSecondaryIndexRelationshipAttributes,
    )
    return DynamoDBSecondaryIndex(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dynamo_db_secondary_index_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dynamo_db_secondary_index_to_nested_bytes(
    dynamo_db_secondary_index: DynamoDBSecondaryIndex, serde: Serde
) -> bytes:
    """Convert flat DynamoDBSecondaryIndex to nested JSON bytes."""
    return serde.encode(_dynamo_db_secondary_index_to_nested(dynamo_db_secondary_index))


def _dynamo_db_secondary_index_from_nested_bytes(
    data: bytes, serde: Serde
) -> DynamoDBSecondaryIndex:
    """Convert nested JSON bytes to flat DynamoDBSecondaryIndex."""
    nested = serde.decode(data, DynamoDBSecondaryIndexNested)
    return _dynamo_db_secondary_index_from_nested(nested)


